   ```rust
   /// Build the logical payload for any RunCommand variant.
   /// The payload goes AFTER the 0x81 0x9F magic header (burst_to_one adds those).
   /// Strings: [string_bytes..., 0x03]. Typed: [0xF0, cmd_id, args..., 0x03].
   pub(crate) fn build_command_data(command: &RunCommand) -> Vec<u8> {
       match command {
           RunCommand::SendMessage(msg) => {
               let mut data = msg.as_bytes().to_vec();
               data.push(ETX_TERMINATOR_BYTE);  // 0x03
               data
           }
           RunCommand::QueryInfo => vec![CMD_DISCRIMINATOR, CMD_QUERY_INFO, 0x03],
           RunCommand::QueryCallback(index) => vec![CMD_DISCRIMINATOR, CMD_QUERY_CALLBACK, *index, 0x03],
           RunCommand::SetOs(os) => vec![CMD_DISCRIMINATOR, CMD_SET_OS, *os as u8, 0x03],
           RunCommand::ApplyHostContext { .. } => /* see S2 */,
           RunCommand::ListDevices => Vec::new(),  // not sent over wire
       }
   }
   ```
