3. LOGIC: Add to src/core.rs:
   ```rust
   /// Parse a raw device reply into a CommandResponse.
   /// response[0]==0x51 => typed reply (decode by response[1])
   /// response[0] in {0,1} => Legacy { matched }
   /// empty/unknown => Timeout
   pub(crate) fn parse_reply(response: &[u8]) -> CommandResponse {
       if response.is_empty() { return CommandResponse::Timeout; }
       match response[0] {
           RESPONSE_MARKER => parse_typed_reply(response),
           0 => CommandResponse::Legacy { matched: false },
           1 => CommandResponse::Legacy { matched: true },
           _ => CommandResponse::Timeout,  // unknown marker => treat as non-capable
       }
   }

   fn parse_typed_reply(response: &[u8]) -> CommandResponse {
       let cmd_echo = response.get(1).copied().unwrap_or(0);
       match cmd_echo {
           CMD_QUERY_INFO => CommandResponse::Info {
               proto_ver: response.get(2).copied().unwrap_or(0),
               feature_flags: response.get(3).copied().unwrap_or(0),
               callback_count: response.get(4).copied().unwrap_or(0),
               board_rules_present: response.get(5).copied().unwrap_or(0) != 0,
           },
           CMD_QUERY_CALLBACK => {
               let index = response.get(2).copied().unwrap_or(0);
               let name = parse_callback_name(&response[3.min(response.len())..]);
               CommandResponse::CallbackName { index, name }
           }
           CMD_SET_OS | CMD_APPLY_HOST_CONTEXT => {
               CommandResponse::Ack { ok: response.get(2).copied().unwrap_or(0) != 0 }
           }
           _ => CommandResponse::Timeout,  // unknown cmd echo
       }
   }
   ```
   parse_callback_name reads ASCII bytes until NUL (0x00) or end of slice, returns None if empty/NUL-at-start. Use String::from_utf8 with .ok() for lossy handling.
   Add exhaustive unit tests with synthetic byte arrays:
   - Info reply [0x51,0x01,2,0x03,5,1] => Info{proto_ver:2, feature_flags:3, callback_count:5, board_rules_present:true}
   - Info reply with board_rules_present=0 => board_rules_present=false
   - CallbackName [0x51,0x02,3,b'V',b'i',b'm',0,0...] => CallbackName{index:3, name:Some("Vim")}
   - CallbackName with NUL at start [0x51,0x02,5,0x00,...] => name:None
   - Ack [0x51,0x03,1] => Ack{ok:true}
   - Ack [0x51,0x05,0] => Ack{ok:false}
